import * as echarts from 'echarts';
export default {
  name: "Home",
  data() {
    return {};
  },
  mounted() {
    //页面元素加载完成后执行

    var option, pie;
    option = {
      title: {
        text: '各季度会员数量统计',
        subtext: '趋势图',
        left: 'center'
      },
      xAxis: {
        type: 'category',
        data: ["第一季度", "第二季度", "第三季度", "第四季度"]
      },
      yAxis: {
        type: 'value'
      },
      series: [{
        data: [],
        type: 'line'
      }, {
        data: [],
        type: 'bar'
      }]
    };
    var chartDom = document.getElementById('main');
    var myChart = echarts.init(chartDom);
    var pieDom = document.getElementById('pie');
    var pieChart = echarts.init(pieDom);
    this.request.get("/echarts/members").then(res => {
      //填空
      //  option.xAxis.data=res.data.x;
      option.series[0].data = res.data;
      option.series[1].data = res.data;
      //数据准备完毕，开始绘制图表
      myChart.setOption(option);
      pie.series[0].data = [{
        name: "第一季度",
        value: res.data[0]
      }, {
        name: "第二季度",
        value: res.data[1]
      }, {
        name: "第三季度",
        value: res.data[2]
      }, {
        name: "第四季度",
        value: res.data[3]
      }];
      pieChart.setOption(pie);
    });
    pie = {
      title: {
        text: '各季度会员数量统计',
        subtext: '比例图',
        left: 'center'
      },
      tooltip: {
        trigger: 'item'
      },
      legend: {
        orient: 'vertical',
        left: 'left'
      },
      series: [{
        type: 'pie',
        radius: '50%',
        label: {
          type: 'pie',
          radius: '60%',
          label: {
            //饼图图形上的文本标签
            normal: {
              show: true,
              position: 'inner',
              //标签的位置
              textStyle: {
                fontWeight: 300,
                fontSize: 16,
                //文字的字体大小
                color: '#fff'
              },
              formatter: '{b}:{d}%'
            }
          }
        },
        data: [],
        emphasis: {
          itemStyle: {
            shadowBlur: 10,
            shadowOffsetX: 0,
            shadowColor: 'rgba(0, 0, 0, 0.5)'
          }
        }
      }]
    };
    pie && piChart.setOption(pie);
  }
};
